def enrich_observation(obs: Observation, tool_input: dict) -> str:
    """
    Convert an observation into a model-friendly string that includes
    context about what was tried, so the model can reason about next steps.
    """
    if obs.obs_type == ObservationType.SUCCESS:
        return str(obs.raw)
    if obs.obs_type == ObservationType.EMPTY:
        return (
            f'The {obs.tool} tool returned no results for input: {tool_input}. '
            'Consider trying different parameters or a different tool.'
        )
    if obs.obs_type == ObservationType.ERROR:
        return (
            f'The {obs.tool} tool failed with: {obs.raw}. '
            'Do not retry the same call. Try an alternative approach.'
        )
    if obs.obs_type == ObservationType.TIMEOUT:
        return (
            f'The {obs.tool} tool timed out. '
            'The operation may have partially succeeded. '
            'Check state before retrying.'
        )
    return str(obs.raw)

from dataclasses import dataclass, field

@dataclass
class EnvironmentState:
    """
    Tracks confirmed side effects so the agent does not retry
    actions that already succeeded.
    """
    confirmed_writes: set[str] = field(default_factory=set)
    failed_tools: dict[str, int] = field(default_factory=dict)  # tool -> fail count
    last_observations: list[Observation] = field(default_factory=list)

    def record(self, obs: Observation) -> None:
        self.last_observations.append(obs)
        if obs.obs_type == ObservationType.STATE_CHANGE:
            self.confirmed_writes.add(obs.tool)
        if obs.obs_type in (ObservationType.ERROR, ObservationType.TIMEOUT):
            self.failed_tools[obs.tool] = self.failed_tools.get(obs.tool, 0) + 1

    def should_skip(self, tool: str) -> bool:
        """True if this tool has failed too many times this run."""
        return self.failed_tools.get(tool, 0) >= 3

    def already_wrote(self, tool: str) -> bool:
        return tool in self.confirmed_writes
